/* Suggested markup: <div class="uiwiki-compact-route-inspector" tabindex="0"><span>Compact Route Inspector</span></div> */
.uiwiki-compact-route-inspector {
  display: grid;
  place-items: center;
  min-height: 11rem;
  padding: 1.25rem;
  border: 1px solid #ececee;
  border-radius: 22px;
  background: #ffffff;
  color: #111111;
  font: 700 1rem/1.2 Inter, system-ui, sans-serif;
  box-shadow: 0 2px 16px rgba(0, 0, 0, 0.04);
  transition: transform 240ms cubic-bezier(.22, 1, .36, 1), box-shadow 240ms ease;
}
.uiwiki-compact-route-inspector > span {
  padding: .75rem 1rem;
  border-radius: 999px;
  background: #d8f34e;
  animation: compact_route_inspector 1.8s ease-in-out infinite alternate;
}
.uiwiki-compact-route-inspector:hover,
.uiwiki-compact-route-inspector:focus-visible {
  transform: translateY(-3px);
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.08);
}
@keyframes compact_route_inspector {
  from { transform: translateY(0) scale(1); }
  to { transform: translateY(-4px) scale(1.025); }
}
@media (prefers-reduced-motion: reduce) {
  .uiwiki-compact-route-inspector, .uiwiki-compact-route-inspector > span { animation: none; transition: none; }
}
